INSERT INTO `about_the_syndicate_8362` (`id`, `date_modified`, `admin_add_id`, `date_created`, `time_stamp`, `deleted`, `restricted`, `title`, `photo`, `photo_in_single`, `summary`, `content`, `mission_icon`, `mission_title`, `mission_content`, `vision_icon`, `vision_title`, `vision_content`) VALUES
(1, '2023-04-20 09:48:18', 1, NULL, '2023-04-20 06:48:18', 0, 0, 'About The Syndicate<>نبذة عن النقابة <>', '1672314974672734692.jpg', '16723050871941345426.jpg', 'Implementing an awareness plan, raising the level of the profession, gathering the energies of workers in the field of technological information sciences, and harnessing them in order to improve the material and legal status of the worker in this profession, his hopes and future aspirations, and defend his rights wherever he is, within the framework of constitutional laws and professional norms and in accordance with national standards.<>تنفيذ خطة توعوية ورفع مستوى المهنة وجمع طاقات العاملين في مجال العلوم المعلوماتية التكنولوجية وتسخيرها في سبيل الارتقاء بالوضع المادي والاعتباري للعامل بهذه المهنة وآماله وتطلعاته المستقبلية والدفاع عن حقوقه أينما كان وذلك في إطار القوانين والأعراف المهنية الدستورية ووفق المعايير الوطنية <>', '<p>Implementing an awareness plan, raising the level of the profession, gathering the energies of workers in the field of technological information sciences, and harnessing them in order to improve the material and legal status of the worker in this profession, his hopes and future aspirations, and defend his rights wherever he is, within the framework of constitutional laws and professional norms and in accordance with national standards.</p><><p>تنفيذ خطة توعوية ورفع مستوى المهنة وجمع طاقات العاملين في مجال العلوم المعلوماتية التكنولوجية وتسخيرها في سبيل الارتقاء بالوضع المادي والاعتباري للعامل بهذه المهنة وآماله وتطلعاته المستقبلية والدفاع عن حقوقه أينما كان وذلك في إطار القوانين والأعراف المهنية الدستورية ووفق المعايير الوطنية </p><>', '1672310118459837457.png', 'Mission<>الرسالة<>', '<p dir=\"ltr\">Implementing an awareness plan, raising the level of the profession, gathering the energies of workers in the field of technological informatics sciences, and harnessing them in order to improve the material and legal status of the worker in this profession, his hopes and future aspirations, and defend his rights wherever he is, within the framework of constitutional professional laws and customs and in accordance with current national and international standards. Enhancing the role of technological informatics in public and official life and the Palestinian national economy.</p><><p>تنفيذ خطة توعوية ورفع مستوى المهنة وجمع طاقات العاملين في مجال العلوم المعلوماتية التكنولوجية وتسخيرها في سبيل الارتقاء بالوضع المادي والاعتباري للعامل بهذه المهنة وآماله وتطلعاته المستقبلية والدفاع عن حقوقه أينما كان وذلك في إطار القوانين والأعراف المهنية الدستورية ووفق المعايير الوطنية والعالمية المتداولة. وتعزيز دور المعلوماتية التكنولوجية في الحياة العامة والرسمية والاقتصاد الوطني الفلسطيني.</p><>', '1672310148391653938.png', 'Vission<>الرؤية<>', '<p>To advance the field of informatics and information and communication technology in the State of Palestine and take care of the status of its employees.</p><><p>لنهوض بمجال المعلوماتية وتكنولوجيا المعلومات والاتصالات في دولة فلسطين ورعاية مكانة العاملين بها.</p><>');
