INSERT INTO `mailer_1565894237` (`id`, `date_modified`, `admin_add_id`, `date_created`, `time_stamp`, `deleted`, `restricted`, `email_title`, `module_id`, `module_action`, `from_email`, `include_site_name`, `to_email`, `cc_email`, `bcc_email`, `reply_email`, `content`, `extra_css`) VALUES
(2, '2020-02-14 18:48:12', 1, '2019-08-15 23:47:26', '2020-02-14 18:48:12', 0, 0, 'New Account Info - #website_name#', 468, 1446, NULL, 1, '#email#', '', NULL, '', '<p>Dear #username#,<br /><br />We hope this email will find you well.<br /><br />These are the login information of your account for #website_name# panel:<br /><br />Link:<br /><a title=\"Panel link of #website_name#\" href=\"#panel_link#\">#website_name# - Panel Link</a><br /><br />Username:<br />#username#<br /><br />Password:<br />#password_unhashed#<br /><br />Thank you,<br />#website_name#<br /><br /></p>', ''),
(3, '2019-08-16 12:29:37', 1, '2019-08-16 00:03:19', '2019-08-16 09:29:37', 0, 0, 'Password Reset - #website_name#', 1, 182, NULL, 1, '#email#', '', NULL, '', '<p>Dear #username#,</p>\n\n<p>We hope this email will find you well.</p>\n\n<p>These are the new login information of your account for #website_name# panel:</p>\n\n<p>Link:</p>\n\n<p><strong><a title=\"Panel link of #website_name#\" href=\"#panel_link#\">#website_name# - Panel Link</a></strong></p>\n\n<p>Username:</p>\n\n<p><strong>#username#</strong></p>\n\n<p>Password:</p>\n\n<p><strong>#unhashed_password#</strong></p>\n\n<p>Thank you,</p>\n\n<p>#website_name#</p>', ''),
(1, '2022-10-07 17:34:55', 1, '2019-08-15 23:47:26', '2022-10-07 14:34:55', 0, 0, '#__notification_title# - #website_name#<>#__notification_title# - #website_name#<>', 0, 0, NULL, 1, '#__email#', '', NULL, '', '<p>Dear #__username#,<br /><br />We hope this email will find you well.</p>\r\n<p><strong>#__notification#</strong><br /><br />Have a good day,<br />#website_name#<br /><br /></p><><p style=\"text-align: right;\">السيد\\ة #__username#،</p>\r\n<p dir=\"rtl\" style=\"text-align: right;\">نتمنى أنك بخير.</p>\r\n<p dir=\"rtl\" style=\"text-align: right;\"><strong>#__notification#</strong></p>\r\n<p dir=\"rtl\" style=\"text-align: right;\">&nbsp;</p>\r\n<p dir=\"rtl\" style=\"text-align: right;\">يومك سعيد،</p>\r\n<p dir=\"rtl\" style=\"text-align: right;\">#website_name#</p><>', ''),
(4, '2023-10-26 13:31:37', 1, '2023-04-20 10:40:51', '2023-10-26 10:31:37', 0, 0, 'Your account has been activated<>تم تفعيل حسابك<>', 835, 0, '', 1, '#useremail#', '', '', '', '<p>Hello; </p>\r\n<p dir=\"ltr\">We hope this email will find you will,</p>\r\n<p dir=\"ltr\">Please note that your &nbsp;account on this email #useremail# has been activated,&nbsp; please check out website.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>Thank you</p><><p>مرحبا :</p>\r\n<p dir=\"rtl\">تم تفعيل حسابك يرجى المتابعة.</p><>', ''),
(5, '2024-07-09 10:48:05', 1, '2023-05-10 13:10:44', '2024-07-09 07:48:05', 0, 0, 'new account<>حساب جديد<>', 840, 5089, '', 1, 'info@palist.ps,#email#', '', '', '', '<><p dir=\"rtl\">مرحبا</p>\r\n<p dir=\"rtl\">تم انشاء حساب جديد&nbsp;</p>\r\n<div>\r\n<div>&nbsp;</div>\r\n<div>Username:&nbsp; #username#</div>\r\n<div>Email:&nbsp; #email#</div>\r\n</div><>', ''),
(6, '2023-09-11 14:48:08', 1, '2023-05-14 12:08:19', '2023-09-11 11:48:08', 0, 0, 'Edit Account<><>', 835, 5063, '', 1, 'info@palist.ps', '', '', '', '<p>#username# submitted his form</p><><>', ''),
(7, '2023-06-21 11:55:42', 1, '2023-05-16 10:49:24', '2023-06-21 08:55:42', 0, 0, 'Message from contact form<><>', 809, 4929, '', 1, 'info@palist.ps', '', '', '', '<p>Hello,</p>\r\n<p>name: #name#</p>\r\n<p> </p>\r\n<p>Mobile Number : #mobile_number#</p>\r\n<p> </p><><>', ''),
(8, '2023-05-16 11:51:00', 1, '2023-05-16 11:32:43', '2023-05-16 08:51:00', 0, 0, 'Password Reset - #website_name#<><>', 0, 0, '', 1, '#email_address#', '', '', '', '<p>Dear #full_name#,</p>\r\n<p>We hope this email will find you well.</p>\r\n<p>These are the new login information of your account for #website_name#:</p>\r\n<p>Password:</p>\r\n<p><strong>#unhashed_password#</strong></p>\r\n<p>&nbsp;</p>\r\n<p>Thank you,</p>\r\n<p>#website_name#</p><><>', ''),
(9, '2023-09-11 14:47:33', 1, '2023-04-20 10:40:51', '2023-09-11 11:47:33', 0, 0, 'Your account has been approved<>تم تفعيل حسابك<>', 840, 0, '', 1, '#useremail#', '', '', '', '<p dir=\"ltr\">Hello;</p>\r\n<p dir=\"ltr\">We hope this email will find you will,</p>\r\n<p dir=\"ltr\">Please note that your  account on this email #useremail# has been approved,  please check out website.</p>\r\n<p> </p>\r\n<p>Thank you</p><><p>مرحبا :</p>\r\n<p dir=\"rtl\">تم تفعيل حسابك يرجى المتابعة.</p><>', ''),
(10, '2023-10-26 09:33:15', 1, '2023-07-12 11:15:41', '2023-10-26 06:33:15', 0, 0, 'Join Request Form<><>', 835, 5059, '', 1, 'info@palist.ps', '', '', '', '<p>#email_address# submitted his form</p>\r\n<p>&nbsp;</p><><>', '');
