INSERT INTO `members_8364` (`id`, `date_modified`, `admin_add_id`, `date_created`, `time_stamp`, `deleted`, `restricted`, `name`, `job_name`, `photo`, `summary`, `content`, `order_number`) VALUES
(1, '2023-05-11 11:49:43', 1, '2023-01-03 14:02:30', '2023-05-11 08:49:43', 0, 0, 'Haneen Sawalmeh<>أ٠ حنين سوالمة<>', 'Treasurer of syndicate <>أمين الصندوق<>', '16727470881889924326.png', 'Graduate of computer information systems from An-Najah National University, head of the programming and technical support department in a governmental institution, a member of the Palestinian Technological Information Sciences Union with the title of', '<p>Graduate of computer information systems from An-Najah National University, head of the programming and technical support department in a governmental institution, a member of the Palestinian Technological Information Sciences Union with the title of treasurer.</p><>خريجة أنظمة معلومات حاسوبية من جامعة النجاح الوطنية، رئيس قسم البرمجة والدعم الفني في مؤسسة حكومية، عضو من أعضاء نقابة العلوم المعلوماتية التكنولوجية الفلسطينية بمسمى امين الصندوق.<>', '3'),
(2, '2023-05-11 11:41:41', 1, '2023-01-03 14:03:35', '2023-05-11 08:41:41', 0, 0, 'Musa Abu Sharar<>أ٠ موسى أبو شرار<>', 'Secretary of the syndicate<>أمين السر<>', '1672747412627764599.png', 'Musa Mahmoud Musa Abu Sharar, I was born in Amman in 1970, and studied there until I graduated from Princess Sumaya University for Technology, the first class of computer science in 1995.<><>', 'Musa Mahmoud Musa Abu Sharar, I was born in Amman in 1970, and studied there until I graduated from Princess Sumaya University for Technology, the first class of computer science in 1995. He is married and has three male children and three female children. I live in my beautiful city, Dora, south of Hebron. She obtained a master\'s degree in information systems from the Arab Academy for Banking and Financial Sciences, Amman, the Hashemite Kingdom of Jordan, in 2004.\r\nI returned to the beloved homeland in 1996 with the returnees. I worked from 1996 in the Palestinian Ministry of Interior as a computer programmer. I had the honor to participate in the establishment and operation of the population registration system, civil status and passports until 2001. Since 2004, I have been working at Al-Quds Open University as a faculty member so far in the Dora branch\r\nI loved this land and I have an interest in agriculture, especially vineyards and the blessed olive tree. I love helping people, as I am a volunteer in the Palestinian Red Crescent.\r\nI hope that my country becomes better, more beautiful, and developed with technology and informatics, and in all areas of life. Therefore, I am a member of the Palestinian Syndicate of Technological Informatics Sciences. I always strive for national advancement and progress despite all circumstances, especially in the field of technology and informatics<>موسى محمود موسى ابو شرار ولدت في عمان عام 1970، ودرست بها حتى تخرجت من جامعة الاميرة سمية للتكنولوجيا اول دفعة علوم حاسبات عام 1995 .متزوج ولي من الابناء الذكور ثلاثة والاناث ثلاثة. اسكن في مدينتي الجميلة دورا جنوب الخليل . حصلت على ماجستير انظمة معلومات من الاكاديمية العربية للعلوم المالية والمصرفية عمان المملكة الاردنية الهاشمية عام 2004\r\nعدت الى ارض الوطن الحبيب عام 1996 مع العائدين وعملت من عام 1996 في وزارة الداخلية الفلسطينية كمبرمج حاسبات وكان لي الشرف في المشاركة بالتأسيس وتشغيل نظام تسجيل السكان الاحوال المدنية والجوازات حتى عام 2001 . ومنذ 2004 اعمل في جامعة القدس المفتوحة كعضو هيئة تدريس حتى الان في فرع دورا\r\nاحببت هذه الارض ولي اهتمام في الزراعة وخاصة كروم عنب والشجرة المباركة الزيتون ، احب مساعدة الانسان فانا متطوع في الهلال الاحمر الفلسطيني.\r\nاتمنى ان يصبح وطني احسن واجمل ومتطور بالتكنولوجيا والمعلوماتية و في كل مجالات الحياة لذلك انا عضو في نقابة العلوم المعلوماتية التكنولوجية الفلسطينية . واسعى دائما لرقي وتقدم وطني رغم كل الظروف وخاصة في مجال التكنولوجيا والمعلوماتية<>', '2'),
(3, '2025-08-05 13:00:15', 1, '2023-01-03 14:05:50', '2025-08-05 10:00:15', 0, 0, 'Dr. Maysoun Ibrahim<>د٠ميسون ابراهيم<>', 'President of syndicate <>النقيب<>', '167274749378388551.jpg', 'Dr. Maysoun Ibrahim is the founder and president of the Palestinian Syndicate for Informatics and Technology and a member of the Board of Trustees of the Arab American University in Palestine.<><>', '<p>Dr. Maysoun Ibrahim is the founder and president of the Palestinian Syndicate for Informatics and Technology and a member of the Board of Trustees of the Arab American University in Palestine. She is an expert in ICT for development with experience working in government, international institutions, academia and the private sector. Dr. Ibrahim is a member of the Board of Directors of the Supreme Council for Creativity and Excellence in Palestine, and chairs the Experimental Development and Incubation Committee and the Creativity Supporters Network of the Council. She previously chaired the Fourth National Forum on the Fourth Industrial Revolution in 2019. She is also a member of the Board of Directors of the Euro-Mediterranean University in Slovenia and worked as a consultant To the United Nations ESCWA Organization (UN-ESCWA) in the field of smart sustainable cities and smart digital solutions for urban resilience in the Arab countries. Dr. Ibrahim is a member of many national and international committees and councils, including, but not limited to, the Technical Committee of the ESCWA Technology Center, the Coordinating Committee for Industrial Research Centers in the Arab Countries, the National Committee for the Implementation of the 2030 Agenda and the Sustainable Development Goals of the United Nations, and the Steering Committee For the work of the National Team on Artificial Intelligence, and the Board of the Holt Prize Foundation.&lt;&gt;الدكتورة ميسون إبراهيم هي مؤسس ونقيب نقابة العلوم المعلوماتية التكنولوجية الفلسطينية وعضو في مجلس أمناء الجامعة العربية الأمريكية في فلسطين. هي خبيرة في تكنولوجيا المعلومات والاتصالات من أجل التنمية ولديها خبرة في العمل في الحكومة والمؤسسات الدولية والأوساط الأكاديمية والقطاع الخاص. الدكتورة إبراهيم عضو في مجلس إدارة المجلس الأعلى للإبداع والتميز في فلسطين، وترأس لجنة التطوير التجريبي والاحتضان وشبكة داعمي الإبداع التابعتين للمجلس، وقد ترأست سابقًا المنتدى الوطني الرابع عن الثورة الصناعية الرابعة في العام 2019. وهي أيضاَ عضو في مجلس إدارة الجامعة الأورومتوسطية في سلوفينيا وعملت مستشارة لمنظمة لإسكوا التابعة للأمم المتحدة (UN-ESCWA) في مجال المدن الذكية المستدامة والحلول الرقمية الذكية من أجل المرونة الحضرية في الدول العربية. الدكتورة إبراهيم عضو في العديد من اللجان والمجالس الوطنية والدولية بما في ذلك، على سبيل الذكر لا الحصر، اللجنة الفنية لمركز الإسكوا للتكنولوجيا، واللجنة التنسيقية لمراكز البحوث الصناعية في الدول العربية، واللجنة الوطنية لتنفيذ أجندة 2030 وأهداف التنمية المستدامة المرتبة بها للأمم المتحدة، واللجنة التوجيهية لأعمال الفريق الوطني للذكاء الاصطناعي، ومجلس مؤسسة جائزة هولت.&lt;&gt;</p>', '1'),
