INSERT INTO `other_laws_8419` (`id`, `date_modified`, `admin_add_id`, `date_created`, `time_stamp`, `deleted`, `restricted`, `title`, `summary`, `content`) VALUES
(89, '2023-09-13 10:07:13', 4, '2023-09-13 10:05:12', '2023-09-13 07:07:13', 0, 0, '<>قانون الاتصالات وتكنولوجيا المعلومات<>', '<>الوزارة: وزارة الاتصالات وتكنولوجيا المعلومات. الهيئة: هيئة تنظيم قطاع الاتصالات. المجلس: مجلس إدارة هيئة تنظيم قطاع الاتصالات. رئيس المجلس: رئيس مجلس إدارة هيئة تنظيم قطاع الاتصالات. المدير: المدير التنفيذي للهيئة. الشخص: الشخص الطبيعي أو المعنوي. الرخصة: الشهادة الصادرة عن الهيئة بأن الشخص قد استوفى الشروط القانونية للسماح له بإنشاء أو تشغيل أو إدارة شبكة اتصالات عامة، أو تقديم خدمات اتصالات عامة، أو استخدام ترددات راديوية أو موجات راديوية، أو وفق أحكام هذا القرار بقانون والتشريعات الصادرة بمقتضاه<>', '<><center>\r\n<h1>قرار بقانون رقم (37) لسنة 2021 بشأن الاتصالات وتكنولوجيا المعلومات</h1>\r\n</center>\r\n<p>رئيـــــــــــــــــــــــــــــس دولـــــــــــــــــــــــــــــــة فـلـسـطـــــــــــــــــــــــــين رئيس اللجنة التنفيذية لمنظمة التحرير الفلسطينية استنادًا للنظام الأساس لمنظمة التحرير الفلسطينية وللقانون الأساسي المعدل لسنة 2003م وتعديلاته، وبعد الاطلاع على قانون رقم (3) لسنة 1996م بشأن الاتصالات السلكية واللاسلكية، وعلى القرار بقانون رقم (15) لسنة 2009م بشأن الهيئة الفلسطينية لتنظيم قطاع الاتصالات، وعلى القرار بقانون رقم (15) لسنة 2017م بشأن المعاملات الإلكترونية ، وعلى القرار بقانون رقم (10) لسنة 2018م بشأن الجرائم الإلكترونية وتعديلاته، وبناءً على تنسيب مجلس الوزراء بتاريخ 15/03/2021م، وعلى الصلاحيات المخولة لنا، وتحقيقًا للمصلحة العامة، أصدرنا القرار بقانون الآتي:</p>\r\n<center><br /><span style=\"font-size: large;\"><strong>الفصل الأول</strong></span><br />أحكام عامة</center>\r\n<p><a name=\"A17557_1\"></a></p>\r\n<center><span style=\"color: black;\">مادة (1)</span></center>\r\n<p><a name=\"A17557_1\"></a></p>\r\n<div><span style=\"color: black;\">يكون للكلمات والعبارات الواردة في هذا القرار بقانون المعاني المخصصة لها أدناه، ما لم تدل القرينة على خلاف ذلك: الدولة: دولة فلسطين. مجلس الوزراء: مجلس وزراء دولة فلسطين. الوزير: وزير الاتصالات وتكنولوجيا المعلومات. الوزارة: وزارة الاتصالات وتكنولوجيا المعلومات. الهيئة: هيئة تنظيم قطاع الاتصالات. المجلس: مجلس إدارة هيئة تنظيم قطاع الاتصالات. رئيس المجلس: رئيس مجلس إدارة هيئة تنظيم قطاع الاتصالات. المدير: المدير التنفيذي للهيئة. الشخص: الشخص الطبيعي أو المعنوي. الرخصة: الشهادة الصادرة عن الهيئة بأن الشخص قد استوفى الشروط القانونية للسماح له بإنشاء أو تشغيل أو إدارة شبكة اتصالات عامة، أو تقديم خدمات اتصالات عامة، أو استخدام ترددات راديوية أو موجات راديوية، أو وفق أحكام هذا القرار بقانون والتشريعات الصادرة بمقتضاه. المرخص له: الشخص الذي حصل على الرخصة من الهيئة وفقًا لأحكام هذا القرار بقانون. المخالف: كل شخص مرخص له وخالف أحكام وشروط الترخيص الواردة في هذا القرار بقانون والتشريعات الصادرة بمقتضاه. الجزاءات: التدابير التي تتخذها الهيئة بحق المرخص له المخالف بموجب الرخصة وفقًا لأحكام هذا القرار بقانون . الترددات: خاصية انتشار موجات الراديو وتتمثل في عدد ذبذبات الموجة لكل وحدة زمنية واحدة ، وتقاس بالهيرتز. طيف التردد: الموجات الراديوية \"الموجات الهيرتزية\" التي تتراوح تردداتها بين 3 كيلو هيرتز وثلاثة آلاف جيجا هيرتز، وتنتشر في الفضاء دون موجه صناعي . تخصيص التردد: منح المرخص له حيز من التردد من أجل استخدام ترددات محددة وفقًا لشروط تضعها الهيئة. حيز التردد: جزء من طيف التردد يبدأ بتردد وينتهي بتردد آخر . التصريح: الإذن الذي تمنحه الهيئة إلى المرخص له أو الشخص، لإنشاء أو تشغيل أو إدارة شبكة اتصالات خاصة أو القيام بأي أعمال تحضيرية خاصة بها، وفقًا لأحكام هذا القرار بقانون والتشريعات الصادرة بمقتضاه . المشترك: أي شخص متعاقد مع المرخص له بهدف الحصول على خدمات اتصالات عامة. المستفيد: الشخص غير المشترك الذي ينتفع من خدمة الاتصالات العامة باستخدام عمليات الاتصال. النفاذ: توفير التسهيلات أو الخدمات للمرخص لهم الآخرين بشروط محددة على أساس حصري أو غير حصري، بغرض تقديم خدمات اتصالات، وبما يشمل مختلف عناصر الشبكة ومكوناتها. الربط البيني: الربط الفيزيائي والتقني لمنظومات الاتصالات لتمكين المشتركين من أحد منظومات الاتصالات، بالاتصال بمشتركين في نفس منظومة الاتصالات أو منظومات اتصالات أخرى أو النفاذ للخدمات التي يقدمها المرخص له الآخر . المرخص له المهيمن: المرخص له الذي تصنفه الهيئة أو صنفته الوزارة سابقًا على أنه مرخص له رئيسي في واحد أو أكثر من أسواق خدمات الاتصالات، والذي يمتلك في أي وقت من الأوقات نسبة محددة تحددها الهيئة بالتنسيق مع الجهات الرسمية المختصة من الحصة السوقية في أي من أسواق خدمات الاتصالات أو أي سوق آخر تحدده الهيئة، أو أي نسبة أخرى تعتمدها بناءً على مراجعة تحليلية لأسواق الاتصالات وفق الأصول التنظيمية المعتمدة. العرض المرجعي للربط البيني: نشرة متوفرة للعامة يقوم بإعدادها المرخص له المهيمن، وتعتمد من المنظم، يعرّف فيها على عدد من العوامل الفنية والتجارية القياسية التي يعرض بها المرخص له المهيمن خدمات الربط البيني للمرخص لهم الآخرين، وتقوم على أساس شفافية عرض المرخص له المهيمن للتعاقد مع أطراف أخرى من خلال اتفاقية ربط بيني. شبكة الاتصالات العامة: منظومة أو مجموعة من منظومات الاتصالات المعدة لتقديم خدمات الاتصالات العامة وفقًا لأحكام هذا القرار بقانون. شبكة الاتصالات الخاصة: منظومة اتصالات تشغل لمصلحة شخص واحد، أو مجموعة من الأشخاص تجمعهم ملكية مشتركة لخدمة حاجاتهم الخاصة. الاتصالات: نقل أو إرسال أو استقبال أو بث أو تمرير الصوت، والبيانات، والإشارات، والرموز ، والفيديو، والصور بوسائل سلكية أو لاسلكية أو راديوية أو بصرية أو كهرومغناطيسية أو أي وسيلة أخرى للاتصالات. خدمة الاتصالات: الخدمة التي تتكون كليًا أو جزئيًا من إرسال المعلومات أو البيانات أو استقبالها أو تمريرها على شبكات الاتصالات باستخدام أي من عمليات الاتصالات. خدمة الاتصالات العامة: خدمة الاتصالات المقدمة للمشتركين والمرخص لهم الآخرين مقابل أجر ، والاتجار واستيراد أجهزة الاتصالات السلكية واللاسلكية وتصنيعها. مزود خدمة الاتصالات: الشخص المرخص له لتزويد خدمات الاتصالات العامة لأي جهة وبأي وسيلة وفقًا لأحكام هذا القرار بقانون والتشريعات الصادرة بمقتضاه. أجهزة الاتصالات: الأجهزة التي تستخدم في نقل أو إرسال أو استقبال أو بث أو تمرير الصوت ، والبيانات، والإشارات، والرموز، والفيديو، والصور بوسائل سلكية أو لاسلكية أو راديوية أو بصرية أو كهرومغناطيسية أو أي وسيلة أخرى للاتصالات. أجهزة الاتصالات الطرفية: أي جهاز يستخدم من قبل المشترك أو المستفيد للربط مع نهاية نقطة لشبكة اتصالات من أجل إرسال أو بث أو استقبال أو إنهاء خدمات الاتصالات. شمولية الخدمة: توفير خدمات الاتصالات العامة في المناطق والتجمعات السكانية بما فيها المناطق النائية والمهمشة، وتسهيل إيصال خدمات الاتصالات واستخدامها وفقًا لسياسة شمولية الخدمة. محطة راديوية: جهاز إرسال أو استقبال أو أكثر أو تكوين مشترك منها، بما في ذلك الأجهزة المساعدة ثابتة كانت أو متحركة من أجل تقديم خدمات الاتصالات الراديوية. الجدول الوطني لتوزيع الترددات: الجدول الذي يتضمن توزيع طيف الترددات إلى حزم لاستخدامها للاتصالات اللاسلكية بما يتفق مع جدول توزيع الترددات الصادر عن الاتحاد الدولي للاتصالات. الخطة الوطنية للترددات \"المخطط الوطني لتوزيع الترددات\": المعايير الفنية المعتمدة لاستخدام حزم الترددات الواردة في الجدول الوطني لتوزيع الترددات، مع مراعاة متطلبات الأمن الوطني في استخدام تلك الحزم. السجل الوطني لتخصيص الترددات: سجل خاص يحتوي على جميع المعلومات المتعلقة باستخدام الترددات التي تم تخصيصها للمحطات الراديوية. الترقيم: نسق من الرموز أو الأرقام المتسلسلة يحدد نقطة نهاية في شبكة الاتصالات ويتضمن المعلومات الضرورية لتوجيه الاتصالات إلى هذه النقطة. الموافقة الخاصة: الموافقة التي تصدر عن الهيئة للشخص باستعمال أنواع محددة من أجهزة الاتصالات وأجهزة الاتصالات الطرفية، أو تكنولوجيا المعلومات، والسماح بإدخالها إلى أراضي الدولة. تكنولوجيا المعلومات: أي وسيلة إلكترونية مغناطيسية بصرية كهروكيميائية أو أي وسيلة أخرى ، سواء كانت مادية أم غير مادية، أو مجموعة وسائل مترابطة أو غير مترابطة تستخدم لمعالجة البيانات وأداء المنطق والحساب أو الوظائف التخزينية، وتشمل أي قدرة تخزين بيانات أو اتصالات تتعلق أو تعمل بالاقتران مع مثل هذه الوسيلة.</span></div>\r\n<p><a name=\"A17557_2\"></a></p>\r\n<center><span style=\"color: black;\">مادة (2)</span></center>\r\n<p><a name=\"A17557_2\"></a></p>\r\n<div><span style=\"color: black;\">يهدف هذا القرار بقانون إلى تحقيق الآتي: تنظيم قطاعي الاتصالات وتكنولوجيا المعلومات بما يواكب التطور التكنولوجي، لضمان تزويد خدمات اتصالات وتكنولوجيا معلومات عالية الجودة بشروط وأسعار تنافسية مناسبة وعادلة. 2. الرقابة على أداء المرخص لهم، وحماية مصالح المشتركين والمستفيدين من خدمات الاتصالات وتكنولوجيا المعلومات. 3. خلق بيئة تنافسية لإنشاء شبكات الاتصالات وتزويد خدمات الاتصالات وتكنولوجيا المعلومات ومنع الاحتكار.. 4.تشجيع الاستثمار في قطاعي الاتصالات وتكنولوجيا المعلومات، وضمان حماية المستثمرين. 5.ضمان وصول خدمات الاتصالات إلى كافة مناطق الدولة وذلك من خلال تحقيق شمولية خدمات الاتصالات. 6.بناء وتطوير وتنمية الإبداع والابتكار في صناعة الاتصالات ونظم تكنولوجيا المعلومات.</span></div>\r\n<p><a name=\"A17557_2\"></a></p>\r\n<center><br /><span style=\"font-size: large;\"><strong>الفصل الثاني</strong></span><br />تنظيم قطاع الاتصالات وتكنولوجيا المعلومات</center>\r\n<p><a name=\"A17557_2\"></a><a name=\"A17557_3\"></a></p>\r\n<center><span style=\"color: black;\">مادة (3)</span></center>\r\n<p><a name=\"A17557_3\"></a></p>\r\n<div><span style=\"color: black;\">تتولى الوزارة القيام بالمهام الآتية: 1.إعداد السياسة العامة لقطاعي الاتصالات وتكنولوجيا المعلومات، وعرضها على مجلس الوزراء لاعتمادها، ووضع خطة استراتيجية وطنية وفقًا لهذه السياسية ومتابعة تطبيقها. 2.إعداد سياسة شمولية الخدمة وتطويرها وتقديمها للهيئة لتنفيذها، ومتابعة تنفيذ الهيئة لها. 3.وضع خطط لتشجيع الاستثمار في قطاعي الاتصالات وتكنولوجيا المعلومات، بما يضمن خلق بيئة تنافسية بين المرخص لهم. 4.اقتراح مشاريع القوانين والأنظمة المتعلقة بقطاعي الاتصالات وتكنولوجيا المعلومات إلى مجلس الوزراء. 5.العمل على إزالة أي عوائق أمام قطاعي الاتصالات وتكنولوجيا المعلومات بالتنسيق مع الهيئة. 6.متابعة تنفيذ التزامات الدولة بموجب الاتفاقيات الدولية التي ترتبط بها في مجال الاتصالات وتكنولوجيا المعلومات، ورعاية مصالح الدولة لدى الدول والمنظمات والهيئات والاتحادات المعنية بشؤون الاتصالات وتكنولوجيا المعلومات. 7.تعزيز مكانة الدولة على المستوى الدولي في مجال الاتصالات وتكنولوجيا المعلومات بكافة السبل الممكنة، لا سيما من خلال نشر البيانات والمعلومات وفق المؤشرات المعتمدة عالميًا لدى الجهات الدولية والمحلية في كافة المنصات ذات العلاقة . 8.إعداد مؤشرات الأداء الوطنية في مجال الاتصالات وتكنولوجيا المعلومات. 9.اعداد دراسة لتعريف وتحديد أسواق الاتصالات ومراجعتها كلما دعت الحاجة الى ذلك ، وتحديد المرخص له المهيمن في تلك الأسواق، وتعتبر مخرجات الدراسة ملزمة للمرخص له . 10.خلق بيئة عمل متكاملة لتطوير التقنيات المتعلقة بالاتصالات وتكنولوجيا المعلومات والابتكار والبحوث المتعلقة بها بالتعاون مع جهات الاختصاص. 11.الرقابة على أداء الهيئة في مجال تنظيم قطاع الاتصالات، بما يضمن قيامها بالمهام المحددة لها وفقًا لأحكام هذا القرار بقانون . 12.أي مهام أخرى واردة في أحكام هذا القرار بقانون أو التشريعات ذات العلاقة النافذة أو التي تكلف بها من مجلس الوزراء.</span></div>\r\n<p><a name=\"A17557_4\"></a></p>\r\n<center><span style=\"color: black;\">مادة (4)</span></center>\r\n<p><a name=\"A17557_4\"></a></p>\r\n<div><span style=\"color: black;\">تنشأ بموجب أحكام هذا القرار بقانون هيئة تسمى \"هيئة تنظيم قطاع الاتصالات\"، تتمتع بالشخصية الاعتبارية، والذمة المالية، والأهلية القانونية الكاملة لمباشرة جميع الأعمال والتصرفات التي تكفل تحقيق الأغراض التي قامت من أجلها، بما في ذلك تملك الأموال المنقولة وغير المنقولة، واستئجارها ،وفتح الحسابات البنكية بالقدر اللازم لسير أعمالها وممارسة نشاطاتها، والتعاقد مع الغير، والقيام بجميع التصرفات القانونية اللازمة لتحقيق أهدافها، بما في ذلك قبول الهبات والتبرعات والمنح غير المشروطة، ويكون للهيئة بند على الموازنة العامة للدولة.</span></div>\r\n<p><a name=\"A17557_5\"></a></p>\r\n<center><span style=\"color: black;\">مادة (5)</span></center>\r\n<p><a name=\"A17557_5\"></a></p>\r\n<div><span style=\"color: black;\">يكون المقر الرئيس والدائم للهيئة في القدس، والمؤقت في كل من مدينتي رام الله وغزة، ولها أن تفتح فروع ومكاتب في أي مدينة أخرى بقرار من المجلس وفقًا لأحكام هذا القرار بقانون.</span></div>\r\n<p><a name=\"A17557_6\"></a></p>\r\n<center><span style=\"color: black;\">مادة (6)</span></center>\r\n<p><a name=\"A17557_6\"></a></p>\r\n<div><span style=\"color: black;\">تتولى الهيئة القيام بالمهام الآتية: 1. تنفيذ السياسة العامة والخطط والبرامج المعتمدة، الخاصة بقطاع الاتصالات. 2.تنظيم خدمات الاتصالات بما يتفق مع السياسة المقرة، لضمان تقديم خدمات الاتصالات للمشتركين بجودة عالية وأسعار تنافسية مناسبة وعادلة مبنية على التكلفة. 3.تنفيذ سياسة شمولية الخدمة. 4.حماية مصالح وخصوصية المشتركين بخدمات الاتصالات. 5.الرقابة على المرخص لهم للتأكد من الالتزام بأحكام هذا القرار بقانون والتشريعات الصادرة بمقتضاه، وشروط الترخيص، واتخاذ الإجراءات اللازمة لتحقيق ذلك. 6.وضع شروط ومعايير منح رخص شبكات وخدمات الاتصالات وتخصيص واستخدام موارد الاتصالات المحدودة كالترددات والأرقام، وإدارة الطيف المرتبط بالترددات. 7.منح الموافقات الخاصة والرخص والتصاريح وتجديدها وتعديلها وإلغائها وفقًا لأحكام هذا القرار بقانون والتشريعات الصادرة بمقتضاه. 8.تحديد معايير جودة الخدمة التي يلتزم المرخص له بتقديمها، بما يضمن تقديم الخدمات بجودة عالية. 9.إيقاع الجزاءات على المرخص لهم المخالفين. 10.وضع أسس ومعايير تحديد أسعار وأجور خدمات الاتصالات المقدمة للمشتركين من المرخص لهم ومراجعتها بما يتفق مع واقع المنافسة والتكلفة. 11.إصدار القواعد الفنية والمقاييس لربط أجهزة الاتصالات السلكية واللاسلكية، بما في ذلك أجهزة الاتصالات الطرفية مع شبكات الاتصالات العامة. 12.إصدار القواعد الفنية المتعلقة بالسلامة العامة الواجب اتباعها عند تركيب وتشغيل واستخدام شبكات وأعمدة وأبراج الاتصالات ومتابعة تنفيذها وتشغيلها، طبقًا للمعايير التي يتم وضعها بالتنسيق مع الجهات المعنية في الدولة. 13.تخصيص وتنظيم وإدارة عنونة أسماء النطاقات الوطنية للنفاذ إلى شبكة المعلومات العالمية \"الإنترنت.\" 14.اعتماد التقنيات الحديثة لمواكبة التطورات التقنية والتكنولوجية في قطاع الاتصالات. 15.إعداد مشاريع القوانين والأنظمة المتعلقة بقطاع الاتصالات بالتنسيق مع الوزارة وفقًا لأحكام هذا القرار بقانون . 16.أي مهام أخرى واردة في هذا القرار بقانون أو التشريعات ذات العلاقة النافذة أو التي تكلف بها من مجلس الوزراء في إطار مواكبة التطور التقني في مجال الاتصالات.</span></div>\r\n<p><a name=\"A17557_7\"></a></p>\r\n<center><span style=\"color: black;\">مادة (7)</span></center>\r\n<p><a name=\"A17557_7\"></a></p>\r\n<div><span style=\"color: black;\">1. يتولى إدارة الهيئة مجلس مكون من تسعة أعضاء، يتم تعيينهم بقرار من مجلس الوزراء على النحو الآتي: &zwnj;أ. مختص في مجال الاتصالات رئيسًا. &zwnj;ب. ممثل عن وزارة الاتصالات وتكنولوجيا المعلومات. &zwnj;ج. ممثل عن وزارة المالية. &zwnj;د. ممثل عن وزارة الاقتصاد الوطني. هـ. ممثل عن وزارة الأشغال العامة. &zwnj;و. ممثل أكاديمي عن الجامعات الفلسطينية مختص في مجال الاتصالات. &zwnj;ز. عضوان من القطاع الخاص، مختصان في مجال الاتصالات. &zwnj;ح. عضو مختص في مجال القانون الخاص . 2. يصدر مجلس الوزراء قرارًا بتسمية ممثلي الحكومة المحددين بالفقرة (1) من هذه المادة ، بناءً على توصية من الوزير المختص، على ألا تقل درجتهم الوظيفية عن مدير عام. 3. تكون مدة العضوية في المجلس أربع سنوات، ويجوز تمديد العضوية للرئيس أو أي من الأعضاء لمدة سنتين ولمرة واحدة فقط، بقرار من مجلس الوزراء. 4. ينتخب المجلس في أول جلسة يعقدها نائبًا لرئيس المجلس من بين أعضائه، ويمارس صلاحيات رئيس المجلس في حال غيابه. 5 يعين المجلس في أول جلسة يعقدها أمينًا للصندوق من بين أعضائه.</span></div>\r\n<p><a name=\"A17557_8\"></a></p>\r\n<center><span style=\"color: black;\">مادة (8)</span></center>\r\n<p><a name=\"A17557_8\"></a></p>\r\n<div><span style=\"color: black;\">1. يشترط فيمن يعين رئيسًا أو عضوًا في المجلس أن يكون: &zwnj;أ. فلسطيني. &zwnj;ب. متمتعًا بالأهلية القانونية، وحسن السيرة والسلوك. &zwnj;ج. حاصلًا على الدرجة الجامعية الأولى كحد أدنى، وتتوافر لديه الخبرة والدراية في مجالات عمل الهيئة لمدة لا تقل عن عشر سنوات، أو حاصلًا على الدرجة الجامعية الثانية ولديه الخبرة والدراية في مجال عمل الهيئة لمدة لا تقل عن خمس سنوات. &zwnj;د. غير محكوم عليه بجنايةٍ أو جنحةٍ مخلة بالشرف أو الأمانة، ما لم يرد إليه اعتباره. هـ. أمضى مدة لا تقل عن سنتين من تاريخ انتهاء عمله في أي شركة عاملة في مجال الاتصالات وتكنولوجيا المعلومات . 2. لا يجوز لرئيس المجلس أو لأي عضو من أعضاءه أو أحد أقربائه للدرجة الثانية، العمل في أي شركة اتصالات ذات علاقة لمدة لا تقل عن سنة بعد انتهاء عضويته في المجلس وفقًا لأحكام هذا القرار بقانون. 3. يحظر على رئيس المجلس أو أي عضو من أعضائه، أن يكون له أو لزوجه أو لأي من أقربائه حتى الدرجة الرابعة خلال مدة العضوية في المجلس أي مصالح أو منافع مباشرة في أي استثمار في مجال قطاع الاتصالات .</span></div>\r\n<p><a name=\"A17557_9\"></a></p>\r\n<center><span style=\"color: black;\">مادة (9)</span></center>\r\n<p><a name=\"A17557_9\"></a></p>\r\n<div><span style=\"color: black;\">يعتبر المجلس السلطة العليا في الهيئة، وصاحب الاختصاص في الإشراف على إدارتها وتنفيذ مهامها واتخاذ القرارات اللازمة لسير أعمالها، ويتولى المجلس المهام والصلاحيات الآتية : 1. تنفيذ السياسة العامة لقطاع الاتصالات المقرة من الوزارة. 2. تنفيذ الخطط والبرامج اللازمة لعمل الهيئة والإشراف على تنفيذها. 3. وضع الأنظمة الداخلية لعمل الهيئة، والإشراف على إدارتها، ومتابعة كافة أنشطتها لضمان تحقيق الأهداف التي أنشئت من أجلها. 4. الموافقة على إصدار الرخص والتصاريح للمرخص لهم أو تجديدها أو إلغائها أو تعديلها أو وقفها وفقًا لأحكام هذا القرار بقانون. 5. مراقبة أداء قطاع الاتصالات ومشغليه، واتخاذ القرارات والإجراءات المناسبة، وتوقيع الجزاءات على المخالفين لشروط الترخيص وأحكام هذا القرار بقانون لضمان حسن الأداء ومنع الاحتكار والمضاربات والتعديات في قطاع الاتصالات. 6. اتخاذ القرارات بشأن إدارة الترددات. 7. الموافقة على استحداث الخدمات الجديدة والرخص الخاصة بها وفقًا لأحكام هذا القرار بقانون. 8. تعيين المفوضين بالتوقيع عن الحسابات البنكية الخاصة بالهيئة، وفتح الحسابات البنكية للهيئة لدى البنوك العاملة داخل الدولة، لتحقيق أهداف الهيئة. 9.التوصية بتعيين المدير. 10.تعيين محاسب قانوني ومدقق حسابات للهيئة . 11.الموافقة على التعاقد مع المؤسسات العلمية المتخصصة والمستشارين والخبراء وغيرهم من ذوي الاختصاص لتقديم الخدمات والدراسات المتعلقة بمهام الهيئة. 12.المصادقة على التقرير المالي والإداري للهيئة. 13.إقرار الهيكل التنظيمي للهيئة، ورفعه لمجلس الوزراء للمصادقة عليه. 14.إقرار الموازنة السنوية للهيئة، ورفعها لمجلس الوزراء للمصادقة عليها وفقًا للقانون. 15. رفع التقارير الربعية والتقرير السنوي عن كافة أعمال المجلس وأنشطة الهيئة إلى مجلس الوزراء والوزارة.</span></div>\r\n<p><a name=\"A17557_10\"></a></p>\r\n<center><span style=\"color: black;\">مادة (10)</span></center>\r\n<p><a name=\"A17557_10\"></a></p>\r\n<div><span style=\"color: black;\">1. يمارس رئيس المجلس الصلاحيات الآتية: &zwnj;أ. دعوة المجلس إلى الانعقاد وإدارة جلساته. &zwnj;ب. متابعة تنفيذ قرارات المجلس. &zwnj;ج. تمثيل الهيئة أمام كافة الجهات الرسمية وغير الرسمية، ويجوز له أن يفوض عضوًا أو أكثر من أعضاء المجلس لهذه الغاية. &zwnj;د. التوقيع على كافة القرارات والتعليمات والوثائق، بما فيها الرخص والتصاريح الصادرة عن المجلس. هـ. أي مهام أخرى يكلف بها من قبل المجلس. 2. يتولى نائب الرئيس ممارسة صلاحيات الرئيس في حال غيابه.</span></div>\r\n<p><a name=\"A17557_11\"></a></p>\r\n<center><span style=\"color: black;\">مادة (11)</span></center>\r\n<p><a name=\"A17557_11\"></a></p>\r\n<div><span style=\"color: black;\">1. يجتمع المجلس بشكل دوري بما لا يقل عن أربعة اجتماعات في السنة، أو كلما اقتضت الحاجة لعقد اجتماع، وذلك بناءً على دعوة من رئيس المجلس أو بطلب يقدم لرئيس المجلس أو نائبه من ثلث الأعضاء على الأقل. 2. يكون اجتماع المجلس قانونيًا بحضور أغلبية أعضائه (05%+1) بمن فيهم رئيس المجلس أو نائبه في حال غيابه. 3. توثق جلسات وقرارات المجلس كتابة، في محاضر رسمية توقع من رئيس المجلس أو نائبه في حال غيابه، والأعضاء الحاضرين. 4. تصدر قرارات المجلس بأغلبية أصوات أعضائه الحاضرين، وإذا تساوت الأصوات يرجح القرار الذي صوت لصالحه رئيس الجلسة. 5 يجوز للمدير حضور جلسات المجلس بدعوة من الرئيس أو نائبه في حال غيابه، دون أن يكون له حق التصويت.</span></div>\r\n<p><a name=\"A17557_12\"></a></p>\r\n<center><span style=\"color: black;\">مادة (12)</span></center>\r\n<p><a name=\"A17557_12\"></a></p>\r\n<div><span style=\"color: black;\">1. تنتهي عضوية أي عضو من أعضاء المجلس في أي من الحالات الآتية: &zwnj;أ. الوفاة. &zwnj;ب. الاستقالة أو الإقالة. ج. انتهاء مدة العضوية وفقًا لأحكام هذا القرار بقانون. د. إذا أعلن إفلاسه أو فقد أهليته القانونية. هـ. إذا أصبح غير قادر على أداء مهامه لأسباب صحية، على أن يثبت ذلك بتقرير صحي صادر عن جهة رسمية . &zwnj;و. إذا حكم عليه بأي جناية أو جنحة مخلة بالشرف أو الأمانة. &zwnj;ز. إذا ثبت أن له منفعة مباشرة، خلافًا لأحكام الفقرة (3) من المادة (8) من هذا القرار بقانون. ح. إذا تخلف عن حضور ثلاث جلسات متتالية أو ستة اجتماعات غير متتالية خلال السنة دون عذر مشروع يقبله المجلس. 2. إذا شغر منصب أي عضو من الأعضاء قبل انتهاء المدة المحددة للعضوية، يعين عضو آخر عوضًا عنه لإكمال المدة المتبقية وفقًا لأحكام الفقرة (3) من المادة (7) من هذا القرار بقانون.</span></div>\r\n<p><a name=\"A17557_13\"></a></p>\r\n<center><span style=\"color: black;\">مادة (13)</span></center>\r\n<p><a name=\"A17557_13\"></a></p>\r\n<div><span style=\"color: black;\">1. يعين المدير حسب درجته وفقًا للقانون بناءً على توصية من المجلس، ويمارس المهام والصلاحيات الآتية: &zwnj;أ. تنفيذ قرارات المجلس. &zwnj;ب. تقديم التوصيات بشأن الخطط والبرامج اللازمة لعمل الهيئة، ورفعها إلى المجلس لإقرارها. &zwnj;ج. إعداد الموازنة السنوية للهيئة، ورفعها للمجلس لإقرارها. &zwnj;د. إعداد التقرير الإداري والمالي للهيئة، ورفعه للمجلس للمصادقة عليه. هـ. إعداد الهيكل التنظيمي للهيئة، ورفعه للمجلس لإقراره. و. أي مهام أخرى يكلف بها من قبل المجلس أو رئيس المجلس. 2. لا يجوز الجمع بين العضوية في المجلس، ومنصب المدير. 3. تسري شروط تعيين رئيس وأعضاء المجلس الواردة في الفقرتين (1، 2) من المادة (8) من هذا القرار بقانون على تعيين المدير. 4. على الرغم مما جاء في الفقرة (1) من هذه المادة، يجوز تعيين المدير وفقًا لنظام توظيف الخبراء وشغل الأعمال المؤقتة العارضة أو الموسمية النافذ.</span></div>\r\n<p><a name=\"A17557_14\"></a></p>\r\n<center><span style=\"color: black;\">مادة (14)</span></center>\r\n<p><a name=\"A17557_14\"></a></p>\r\n<div><span style=\"color: black;\">1. تستوفي الهيئة الرسوم الآتية: أ&zwnj;. رخص الاتصالات ب. الموافقات والتصاريح التي تمنحها الهيئة ج. استخدام وتخصيص الترددات والأرقام وموارد الاتصالات الهامة الأخرى. د. أي عوائد مالية مرتبطة بالرخصة. 2. يحدد مقدار الرسوم وشروط استيفائها بموجب جدول يلحق بهذا القرار بقانون، ويعتبر جزءًا لا يتجزأ منه، وينشر في الجريدة الرسمية.</span></div>\r\n<p><a name=\"A17557_15\"></a></p>\r\n<center><span style=\"color: black;\">مادة (15)</span></center>\r\n<p><a name=\"A17557_15\"></a></p>\r\n<div><span style=\"color: black;\">1. تتكون الموارد المالية للهيئة من الآتي: أ. الأموال المخصصة لها في الموازنة العامة. ب. العائدات المتأتية من الرسوم التي تستوفيها الهيئة وفقًا لأحكام هذا القرار بقانون. ج. العائدات المتأتية من الغرامات المفروضة وفقًا لأحكام هذا القرار بقانون والقوانين ذات العلاقة النافذة واتفاقيات الرخص. د. المنح والهبات غير المشروطة التي لا يمثل قبولها تناقضًا مع مصالح الهيئة ودورها ، ويقرر المجلس قبولها بعد موافقة مجلس الوزراء. هـ. أي موارد أخرى يوافق عليها مجلس الوزراء. 2. تورد جميع مدخولات وإيرادات الهيئة المنصوص عليها في البنود (ب، ج، د، هـ) من الفقرة (1) من هذه المادة إلى الخزينة العامة.</span></div>\r\n<p><a name=\"A17557_16\"></a></p>\r\n<center><span style=\"color: black;\">مادة (16)</span></center>\r\n<p><a name=\"A17557_16\"></a></p>\r\n<div><span style=\"color: black;\">1. تعتبر أموال الهيئة وحقوقها لدى الغير أموالًا عامة تتم جبايتها وتحصيلها وفقًا لأحكام التشريعات النافذة . 2. تودع أموال الهيئة لدى المصارف أو المؤسسات المالية التي يحددها المجلس. 3. للهيئة أن تحتفظ بالسيولة الكافية لتغطية النفقات التشغيلية لمدة شهر. 4. تلتزم الهيئة بإعداد وحفظ سجلات كاملة لجميع النشاطات التي تنفذها، ولجميع المعاملات المالية التي تقوم بها. 5. تخضع الهيئة لأنظمة الرقابة المالية والإدارية المعمول بها في الدولة. 6. تتمتع الهيئة بجميع الامتيازات والإعفاءات التي تتمتع بها الوزارات والمؤسسات العامة . 7. يطبق على موظفي الهيئة قانون الخدمة المدنية ونظام توظيف الخبراء وشغل الأعمال المؤقتة العارضة أو الموسمية النافذ، وعلى معاملات الشراء فيها قانون الشراء العام النافذ والأنظمة الصادرة بمقتضاه.</span></div>\r\n<p><a name=\"A17557_17\"></a></p>\r\n<center><span style=\"color: black;\">مادة (17)</span></center>\r\n<p><a name=\"A17557_17\"></a></p>\r\n<div><span style=\"color: black;\">تبدأ السنة المالية للهيئة في الأول من كانون الثاني من كل سنة، وتنتهي في اليوم الحادي والثلاثين من شهر كانون الأول من السنة ذاتها.</span></div>\r\n<p><a name=\"A17557_18\"></a></p>\r\n<center><span style=\"color: black;\">مادة (18)</span></center>\r\n<p><a name=\"A17557_18\"></a></p>\r\n<div><span style=\"color: black;\">تحدد مكافآت رئيس وأعضاء المجلس الحكوميين وفقًا لنظام مكافآت الموظفين العامين المشاركين في مجالس إدارة المؤسسات العامة والخاصة النافذ، أما بقية أعضاء المجلس فيتم تحديد مكافآتهم بقرار من مجلس الوزراء، شريطة ألا تتجاوز قيمة المكافأة الحد الأعلى لقيمة مكافأة أقرانهم من الأعضاء الحكوميين.</span></div>\r\n<p><a name=\"A17557_18\"></a></p>\r\n<center><br /><span style=\"font-size: large;\"><strong>الفصل الثالث</strong></span><br />شبكات الاتصالات العامة والخاصة والتراخيص والموافقات الخاصة</center>\r\n<p><a name=\"A17557_18\"></a><a name=\"A17557_19\"></a></p>\r\n<center><span style=\"color: black;\">مادة (19)</span></center>\r\n<p><a name=\"A17557_19\"></a></p>\r\n<div><span style=\"color: black;\">1. لا يجوز إنشاء أو تشغيل أو إدارة شبكة اتصالات عامة، أو تزويد خدمات اتصالات، أو استخدام ترددات أو أرقام دون الحصول على رخصة من الهيئة وفق أحكام هذا القرار بقانون والتشريعات الصادرة بمقتضاه. 2. تعتبر الرخصة شخصية غير قابلة للبيع أو التحويل أو التأجير أو التنازل عنها أو إشراك الغير فيها، دون الموافقة المسبقة للهيئة. 3. يلتزم المرخص له بتغطية كامل المنطقة الجغرافية المعينة له بالخدمة المرخصة بموجب الرخصة. 4. يحظر على المرخص له الامتناع أو التأخر عن تزويد الهيئة بأي تقارير أو مستندات أو وثائق أو اتفاقيات أو معلومات أو بيانات تطلبها، وتحدد الهيئة للمرخص له الآلية الواجب عليه اتباعها في تزويدها بما تطلبه والمدة الزمنية المحددة لذلك .</span></div>\r\n<p><a name=\"A17557_20\"></a></p>\r\n<center><span style=\"color: black;\">مادة (20)</span></center>\r\n<p><a name=\"A17557_20\"></a></p>\r\n<div><span style=\"color: black;\">1. تصدر الهيئة تعليمات تحدد أنواع شبكات الاتصالات الخاصة بما يشمل الشروط الفنية والتقنية المتعلقة بإنشائها وتشغيلها، وشروط الموافقة عليها ومنح التصاريح الخاصة بها. 2. يجوز بتصريح إنشاء شبكات الاتصالات الخاصة وتشغيلها دون الحصول على ترخيص من الهيئة، باستثناء الترخيص اللازم لاستخدام الترددات والموجات الراديوية، وللهيئة حق الاطلاع على أي شبكات أو منظومات اتصالات والتقرير بشأنها . 3. يحظر استخدام شبكة الاتصالات الخاصة في تزويد خدمات اتصالات عامة أو ربطها مع شبكة اتصالات عامة دون الحصول على ترخيص أو تصريح وفقًا لأحكام هذا القرار بقانون والتشريعات الصادرة بمقتضاه.</span></div>\r\n<p><a name=\"A17557_21\"></a></p>\r\n<center><span style=\"color: black;\">مادة (21)</span></center>\r\n<p><a name=\"A17557_21\"></a></p>\r\n<div><span style=\"color: black;\">1. تصدر الرخصة عن الهيئة التي تحدد شروط الترخيص ومدة سريانه، ويراعى في إجراءات منح الرخصة الآتي: أ. إتاحة الفرصة لتقديم طلبات الترخيص لكل من تتوفر فيه الشروط التي تحددها الهيئة. ب. معاملة جميع طلبات الترخيص دون تمييز. ج. إصدار الرخص بما يتوافق ومبدأ المساواة والعدالة والشفافية 2. للهيئة ترخيص نوع معين من الخدمات الاتصالات سواء على كامل أراضي الدولة أو جزء منها ، وعليها في هذه الحالة أن تقرر الإعلان عن ذلك بأحد الأساليب الآتية: أ. بموجب عطاء عام، وفق الأسس والشروط التي تحددها الهيئة. ب. فتح باب تقديم الطلبات للترخيص لكل من تتوفر فيه الشروط التي تحددها الهيئة. 3. يجوز للمجلس استبعاد أي شخص أو مرخص له إذا تبين له أن اشتراكه في المنافسة على الرخص الجديدة قد يؤدي إلى احتكار في أي من أسواق الاتصالات، أو يؤدي إلى وضع غير تنافسي. 4. مع مراعاة أي التزامات أخرى منصوص عليها في هذا القرار بقانون والتشريعات الصادرة بمقتضاه، يجب أن تتضمن اتفاقية الترخيص في حدها الأدنى الآتي: أ&zwnj;. الرسوم المستحقة للهيئة عن الرخصة ورسوم تجديدها وأي عوائد أو مبالغ مالية مقطوعة أو دورية يتوجب على المرخص له دفعها. ب&zwnj;. نوع الخدمة المقدمة. ج&zwnj;. مدة الرخصة. د. الحدود الجغرافية لتقديم الخدمة وخطة التغطية والمراحل الزمنية لتنفيذها. هـ. مقاييس جودة وكفاءة الخدمة. و. الالتزام باستمرار تقديم الخدمة والإجراءات الواجبة الاتباع في حال انقطاعها. ز. تحديد آلية تسعير الخدمات وطريقة التحصيل. ح. إتاحة الخدمة خلال مدة معقولة وبدون تمييز. ط. مراعاة متطلبات الخدمة الشاملة. ي. التزام المرخص له بتزويد الهيئة بالتقارير الفنية والمالية وأي تقارير أخرى أو بيانات أو سجلات أو معلومات تطلبها وبالطريقة والمواعيد التي تحددها. ك. التزام المرخص له بتوفير التأمينات والكفالات المالية التي تحدد قيمتها الهيئة كضمان لجودة الخدمة أو دفع أي غرامات أو رد ما يستحقه المشتركون عند إلغاء الرخصة. ل. أي شروط والتزامات أخرى ترى الهيئة إضافتها.</span></div>\r\n<p><a name=\"A17557_22\"></a></p>\r\n<center><span style=\"color: black;\">مادة (22)</span></center>\r\n<p><a name=\"A17557_22\"></a></p>\r\n<div><span style=\"color: black;\">تصدر الهيئة الرخصة المطلوبة في حال توافر شروط منحها، وبعد دفع الرسوم المقررة، وفي حال رفض الطلب على الهيئة إبلاغ صاحب الطلب المرفوض بأسباب الرفض، ويكون قرار الرفض قابلًا للاعتراض عليه أمام المجلس خلال ثلاثين يومًا من تاريخ التبليغ بقرار الرفض، كما ويكون قابلًا للطعن أمام المحكمة المختصة وفقًا للقانون.</span></div>\r\n<p><a name=\"A17557_23\"></a></p>\r\n<center><span style=\"color: black;\">مادة (23)</span></center>\r\n<p><a name=\"A17557_23\"></a></p>\r\n<div><span style=\"color: black;\">1. تصدر الهيئة تعليمات منح الموافقة الخاصة تحدد بموجبها المقاييس والمعايير الفنية التي تطبق على أجهزة الاتصالات وأجهزة الاتصالات الطرفية المسموح إدخالها واستعمالها في الدولة ، للتأكد من عدم إضرارها بشبكات أو خدمات الاتصالات أو بالصحة والسلامة العامة والبيئة. 2. تنسق الهيئة مع مؤسسة المواصفات والمقاييس وسلطة جودة البيئة عند وضعها مقاييس ومعايير أجهزة الاتصالات. 3. يحظر إدخال أو استيراد أي أجهزة اتصالات أو أجهزة اتصالات طرفية إلى الدولة دون الحصول على موافقة نوعية لها من الهيئة، ما لم تكن للاستعمال الشخصي. 4. تصدر الهيئة تعليمات بخصوص شروط وإجراءات استيراد وتصنيع أجهزة الاتصالات وأجهزة الاتصالات الطرفية واستعمالها والمتاجرة بها. 5. يحظر بيع أو تداول أو عرض أو حيازة أجهزة التنصت بأنواعها، ولا يجوز حيازتها أو استخدامها إلا وفقًا للقوانين والتشريعات ذات العلاقة.</span></div>\r\n<p><a name=\"A17557_23\"></a></p>\r\n<center><br /><span style=\"font-size: large;\"><strong>الفصل الرابع</strong></span><br />تجديد الرخص وتعديلها وإلغائها ووقفها</center>\r\n<p><a name=\"A17557_23\"></a><a name=\"A17557_24\"></a></p>\r\n<center><span style=\"color: black;\">مادة (24)</span></center>\r\n<p><a name=\"A17557_24\"></a></p>\r\n<div><span style=\"color: black;\">1. يجب على المرخص له أن يقدم للهيئة طلب تجديد رخصته قبل انتهائها، وتحدد الهيئة شروط وإجراءات ومعايير تجديد الرخص، بموجب تعليمات تصدرها لهذه الغاية. 2. يحق للهيئة رفض تجديد أي رخصة مع إبداء الأسباب، ويكون قرار الرفض قابلًا للاعتراض عليه أمام المجلس خلال ثلاثين يومًا من تاريخ التبليغ بقرار الرفض، كما ويكون قابلًا للطعن به أمام المحكمة المختصة. 3. تعتبر مخالفة المرخص له لأي من أحكام هذا القرار بقانون أو التشريعات الصادرة بمقتضاه أو التشريعات ذات العلاقة أو الرخصة خلال مدة الترخيص سببًا مبررًا لعدم تجديد الرخصة. 4. إذا تم رفض تجديد رخصة لتقديم خدمات الاتصالات الثابتة أو الخلوية المتنقلة أو البنية التحتية للاتصالات، لا يجوز للشخص الذي رفض طلب تجديد رخصته إزالة شبكة أو شبكات الاتصالات التي أنشأها أو أي جزء منها دون موافقة خطية مسبقة من الهيئة. 5. إذا قررت الهيئة الإبقاء على الشبكات المشار إليها في الفقرة (4) من هذه المادة أو أي جزء منها، يتم تقييم هذه الشبكات ماديًا وفقًا لأفضل الممارسات العالمية. 6. لا يحول قرار رفض تجديد الرخصة من المشاركة في المنافسة على الرخص الجديدة، شريطة مرور سنتين على تاريخ رفض تجديد الرخصة.</span></div>\r\n<p><a name=\"A17557_25\"></a></p>\r\n<center><span style=\"color: black;\">مادة (25)</span></center>\r\n<p><a name=\"A17557_25\"></a></p>\r\n<div><span style=\"color: black;\">1. تقوم الهيئة بتعديل شروط وأحكام الرخص الممنوحة سابقًا والاتفاقات الملحقة بها أو بموجب أحكام هذا القرار بقانون، إذا كان التعديل ناتج عن اتفاقيات دولية تكون الدولة طرفًا فيها. 2. يجب على الهيئة قبل التعديل أن تبلغ المرخص له خطيًا بالتعديل وأسبابه، وتحديد المدة الزمنية للتنفيذ. 3 بمراعاة أحكام الفقرة (1) من هذه المادة، لا يجوز تعديل شروط الترخيص لأحد المرخص لهم دون غيره من المرخص لهم بذات نطاق الترخيص.</span></div>\r\n<p><a name=\"A17557_26\"></a></p>\r\n<center><span style=\"color: black;\">مادة (26)</span></center>\r\n<p><a name=\"A17557_26\"></a></p>\r\n<div><span style=\"color: black;\">1. يحق للهيئة وقف نفاذ الرخصة بصورة كلية أو لخدمة أو خدمات معينة أو لمنطقة جغرافية معينة أو إلغاء الرخصة في أي من الحالات الآتية: أ&zwnj;. إذا خالف المرخص له أحكام هذا القرار بقانون، أو التشريعات الصادرة بمقتضاه، أو أي من الشروط أو الالتزامات أو الأحكام المنصوص عليها في الرخصة، أو ألحق ضررًا بالغير، ولم يصوب أوضاعه خلال (30) يومًا من تاريخ تبليغه إنذارًا خطيًا ثانيًا بذلك من قبل الهيئة، ما لم يقدم عذرًا يقبله المجلس. ب&zwnj;. إذا امتنع أو تأخر المرخص له عن تنفيذ قرارات أو تعليمات أو أوامر الهيئة، أو طلباتها التنظيمية، ولم يصوب أوضاعه خلال (30) يومًا من تاريخ تبليغه إنذارًا خطيًا ثانيًا بذلك من قبل الهيئة، ما لم يقدم عذرًا يقبله المجلس. ج. إذا تخلف المرخص له عن دفع أي رسوم أو عوائد أو مبالغ مالية أو غرامات مستحقة عليه بموجب هذا القرار بقانون أو التشريعات ذات العلاقة أو التشريعات الصادرة بمقتضاه أو الرخصة، في الموعد المحدد لدفعها، ولم يصوب أوضاعه خلال (30) يومًا من تاريخ تبليغه إنذارًا خطيًا بذلك، ما لم يقدم عذرًا يقبله المجلس. 2. يتم اتخاذ الإجراءات المنصوص عليها في البنود (أ، ب، ج) من الفقرة (1) من هذه المادة بطريقة تدرجية. 3. تعتبر الرخصة ملغاة حكمًا في حال تصفية أو إفلاس المرخص له أو فقدانه أهليته.</span></div>\r\n<p><a name=\"A17557_27\"></a></p>\r\n<center><span style=\"color: black;\">مادة (27)</span></center>\r\n<p><a name=\"A17557_27\"></a></p>\r\n<div><span style=\"color: black;\">يجب على الشخص الذي ألغيت رخصته التوقف فورًا عن استقبال مشتركين جدد، وعدم تزويد خدمات الاتصالات إلا بالقدر الكافي لتحويل مشتركيه إلى مرخص له آخر وبعد الحصول على موافقة الهيئة الخطية.</span></div>\r\n<p><a name=\"A17557_28\"></a></p>\r\n<center><span style=\"color: black;\">مادة (28)</span></center>\r\n<p><a name=\"A17557_28\"></a></p>\r\n<div><span style=\"color: black;\">لا يجوز للشخص الذي ألغيت رخصته أن يطالب الهيئة باسترداد الرسوم التي دفعها للحصول على الرخصة أو لتجديدها، وله حق اللجوء إلى القضاء.</span></div>\r\n<p><a name=\"A17557_29\"></a></p>\r\n<center><span style=\"color: black;\">مادة (29)</span></center>\r\n<p><a name=\"A17557_29\"></a></p>\r\n<div><span style=\"color: black;\">لا يجوز للشخص الذي ألغيت رخصته أن يتقدم للحصول على رخصة جديدة قبل مضي سنتين على إلغاء رخصته.</span></div>\r\n<p><a name=\"A17557_30\"></a></p>\r\n<center><span style=\"color: black;\">مادة (30)</span></center>\r\n<p><a name=\"A17557_30\"></a></p>\r\n<div><span style=\"color: black;\">لا يحول قرار إلغاء الرخصة دون حق المتضررين والمشتركين من مطالبة الشخص الذي ألغيت رخصته بالتعويض واسترداد الرسوم المدفوعة.</span></div>\r\n<p><a name=\"A17557_31\"></a></p>\r\n<center><span style=\"color: black;\">مادة (31)</span></center>\r\n<p><a name=\"A17557_31\"></a></p>\r\n<div><span style=\"color: black;\">1. للشخص الذي ألغيت رخصته حق الاعتراض خلال شهر من تاريخ تبلغه بالإلغاء. 2. على المجلس إصدار قراره خلال عشرين يومًا من تاريخ تقديم طلب الاعتراض، ويكون القرار قابلًا للطعن أمام المحكمة المختصة وفقًا للقانون.</span></div>\r\n<p><a name=\"A17557_31\"></a></p>\r\n<center><br /><span style=\"font-size: large;\"><strong>الفصل الخامس</strong></span><br />شمولية الخدمة</center>\r\n<p><a name=\"A17557_31\"></a><a name=\"A17557_32\"></a></p>\r\n<center><span style=\"color: black;\">مادة (32)</span></center>\r\n<p><a name=\"A17557_32\"></a></p>\r\n<div><span style=\"color: black;\">تعمل الهيئة على تنفيذ سياسة شمولية خدمات الاتصالات بمراعاة الآتي: 1. تأمين النفاذ المتكافئ إلى خدمات الاتصالات لكافة شرائح المجتمع والتجمعات السكانية بشروط متساوية وبأسعار عادلة ومناسبة. 2. توسيع رقعة انتشار خدمات الاتصالات أفقيًا وعموديًا بشكل يلبي احتياجات التنمية الاقتصادية والاجتماعية الشاملة في جميع مناطق الدولة. 3. تمكين ذوي الإعاقة من الحصول على خدمات الاتصالات بأسعار مخفضة تحددها الهيئة.</span></div>\r\n<p><a name=\"A17557_33\"></a></p>\r\n<center><span style=\"color: black;\">مادة (33)</span></center>\r\n<p><a name=\"A17557_33\"></a></p>\r\n<div><span style=\"color: black;\">1. يجب على الهيئة وضع وإدارة خطة تنفيذ شمولية الخدمة بما يتوافق مع سياسة شمولية الخدمة التي تعدها الوزارة، على أن تدار بشفافية وبدون تمييز وبتنافسية وحيادية. 2. تفرض الهيئة تنفيذ خطة شمولية الخدمة في الرخص الممنوحة أو المجددة أو المعدلة. 3. للهيئة وفي سبيل تزويد خدمات اتصالات في منطقة جغرافية معينة أو لشريحة معينة تطبيق التشريعات ذات العلاقة بالشراء العام النافذة.</span></div>\r\n<p><a name=\"A17557_33\"></a></p>\r\n<center><br /><span style=\"font-size: large;\"><strong>الفصل السادس</strong></span><br />إدارة الترددات</center>\r\n<p><a name=\"A17557_33\"></a><a name=\"A17557_34\"></a></p>\r\n<center><span style=\"color: black;\">مادة (34)</span></center>\r\n<p><a name=\"A17557_34\"></a></p>\r\n<div><span style=\"color: black;\">1. تعد الترددات موردًا هامًا وثروة وطنية تملكها الدولة، يحظر على أي شخص بيعها أو التنازل عنها أو تأجيرها أو استخدامها في غير الغاية المرخصة أو المخصصة من أجلها. 2. تقوم الوزارة بمنح ما يتوفر من الترددات للهيئة لتقوم بتخصيصها للجهات الحكومية والمدنية والمرخص لهم، وإدارتها والرقابة على استخدامها. 3. تلتزم الهيئة بسياسات الوزارة المتعلقة بإدارة الترددات. 4. تقوم الوزارة بالتفاوض مع الاتحاد الدولي للاتصالات أو مؤسساته والدول المجاورة بكل ما يتعلق بإدارة واستخدام الترددات بالتنسيق مع الهيئة .</span></div>\r\n<p><a name=\"A17557_35\"></a></p>\r\n<center><span style=\"color: black;\">مادة (35)</span></center>\r\n<p><a name=\"A17557_35\"></a></p>\r\n<div><span style=\"color: black;\">1. تقوم الوزارة وبالتنسيق مع الهيئة بإعداد الخطة الوطنية للترددات بما يتلاءم والاتفاقيات المبرمة مع الدول المجاورة. 2. تقوم الوزارة بإعداد ونشر الجدول الوطني لتوزيع الترددات بما يتلاءم مع إصدارات ولوائح الاتحاد الدولي للاتصالات. 3. تقوم الهيئة بإعداد السجل الوطني لتخصيص الترددات وتحديثه بشكل دوري، وتزود الوزارة بنسخ عنه.</span></div>\r\n<p><a name=\"A17557_36\"></a></p>\r\n<center><span style=\"color: black;\">مادة (36)</span></center>\r\n<p><a name=\"A17557_36\"></a></p>\r\n<div><span style=\"color: black;\">1. يحظر على أي شخص ودون الحصول على رخصة استخدام الترددات، أو استخدامها لتشغيل خدمات بث إذاعي أو تلفزيوني أو فضائي ثابت أو متحرك. 2. يحظر على أي شخص إدخال أو استعمال أو اقتناء محطة راديوية دون الحصول على رخصة أو تصريح من الهيئة، ويستثنى من ذلك الجهات الحكومية والأمنية الرسمية والعسكرية.</span></div>\r\n<p><a name=\"A17557_37\"></a></p>\r\n<center><span style=\"color: black;\">مادة (37)</span></center>\r\n<p><a name=\"A17557_37\"></a></p>\r\n<div><span style=\"color: black;\">1. يحظر على الطائرات والسفن ووسائل النقل البري الأجنبية استخدام أجهزتها الراديوية لأي أغراض غير الملاحة الجوية والبحرية وعمليات الإنقاذ والطوارئ. 2. تعفى الطائرات والسفن ووسائل النقل البري الأجنبية من الحصول على رخصة استخدام ترددات ، شريطة الآتي: أ&zwnj;. مرورها من الدولة واستخدامها للمطارات والموانئ الفلسطينية. ب&zwnj;. حصولها على رخصة الترددات الراديوي من موطنها.</span></div>\r\n<p><a name=\"A17557_38\"></a></p>\r\n<center><span style=\"color: black;\">مادة (38)</span></center>\r\n<p><a name=\"A17557_38\"></a></p>\r\n<div><span style=\"color: black;\">تعفى الجهات التالية من دفع رسوم رخصة استخدام الترددات وتجدد رخصها تلقائيًا: 1. الجهات الحكومية شريطة الحصول على موافقة الوزارة على استخدام الترددات. 2. السفارات والهيئات الدبلوماسية بشرط المعاملة بالمثل. 3. المنظمات الدولية التابعة لهيئة الأمم المتحدة.</span></div>\r\n<p><a name=\"A17557_39\"></a></p>\r\n<center><span style=\"color: black;\">مادة (39)</span></center>\r\n<p><a name=\"A17557_39\"></a></p>\r\n<div><span style=\"color: black;\">1. للهيئة إخلاء حيز الترددات المخصصة للمرخص له أو أي جزء منها مقابل منحه حيز ترددي آخر يضمن استمراره بتقديم الخدمات. 2. تمنح الهيئة بناءً على قرار من مجلس الوزراء، المرخص له مدة لا تقل عن ثلاث سنوات لتنفيذ إخلاء حيز الترددات وفقًا للفقرة (1) من هذه المادة، باستثناء حالات الإخلاء لغايات تلبية احتياجات الأمن القومي والالتزامات الدولية، حيث تحدد المدة الواجب الإخلاء خلالها.</span></div>\r\n<p><a name=\"A17557_40\"></a></p>\r\n<center><span style=\"color: black;\">مادة (40)</span></center>\r\n<p><a name=\"A17557_40\"></a></p>\r\n<div><span style=\"color: black;\">1. يحق للهيئة سحب الترددات المخصصة لأي مرخص له وفي أي وقت إذا قام باستخدامها لغير الغاية المرخصة أو المخصصة لها، أو في حال عدم استخدامها بكفاءة، وتتولى الهيئة وضع معايير كفاءة استخدام الترددات. 2. يحق للهيئة إلغاء رخصة استخدام الترددات وعدم تجديدها إذا لم يتم استخدام الترددات المخصصة وفقًا لتعليمات تصدرها الهيئة لهذه الغاية.</span></div>\r\n<p><a name=\"A17557_40\"></a></p>\r\n<center><br /><span style=\"font-size: large;\"><strong>الفصل السابع</strong></span><br />سياسة المنافسة والهيمنة في قطاع الاتصالات</center>\r\n<p><a name=\"A17557_40\"></a><a name=\"A17557_41\"></a></p>\r\n<center><span style=\"color: black;\">مادة (41)</span></center>\r\n<p><a name=\"A17557_41\"></a></p>\r\n<div><span style=\"color: black;\">1. يحظر على المرخص له القيام بأي تصرف أو ممارسة أو عمل أو الامتناع عن عمل يكون من شأنه منع المنافسة أو الحد منها أو تشويهها أو إضعافها في أي نشاط تجاري يتعلق بقطاع الاتصالات. 2. يحظر على المرخص لهم عقد أي اتفاقيات ظاهرة أو مبطنة أو ضمنية لتوحيد الأسعار. 3. يحظر على المرخص له الاندماج أو الاستحواذ بكافة أشكاله وأنواعه دون الحصول على موافقة خطية مسبقة من الهيئة. 4. للهيئة صلاحية تحديد التصرفات والممارسات غير التنافسية. 5. تصدر الهيئة تعليمات لحماية المنافسة في قطاع الاتصالات تنظم من خلالها القواعد التي يتم اعتمادها في تحديد التصرفات والممارسات التجارية غير التنافسية والإجراءات العلاجية لها ، بالتنسيق مع الجهات الحكومية المختصة بالمنافسة.</span></div>\r\n<p><a name=\"A17557_42\"></a></p>\r\n<center><span style=\"color: black;\">مادة (42)</span></center>\r\n<p><a name=\"A17557_42\"></a></p>\r\n<div><span style=\"color: black;\">1. يحظر على المرخص له المهيمن أن يستغل موقعه في سوق الاتصالات. 2. تفرض الهيئة أحكامًا خاصة ومشددة وإجراءات علاجية على المرخص له المهيمن، في حال استغلال موقعه في سوق الاتصالات.</span></div>\r\n<p><a name=\"A17557_42\"></a></p>\r\n<center><br /><span style=\"font-size: large;\"><strong>الفصل الثامن</strong></span><br />الربط البيني والنفاذ والمشاركة في البنية التحتية</center>\r\n<p><a name=\"A17557_42\"></a><a name=\"A17557_43\"></a></p>\r\n<center><span style=\"color: black;\">مادة (43)</span></center>\r\n<p><a name=\"A17557_43\"></a></p>\r\n<div><span style=\"color: black;\">يجب على كل مرخص له العمل على إنجاز اتفاقيات ربط بينه وبين المرخص لهم الآخرين حسب متطلبات رخص كل منهم، بحيث تتناول تلك الاتفاقيات جميع الشروط المتعلقة بالنواحي الفنية والتشغيلية والإدارية والمالية والتجارية التي تضمن المرونة اللازمة للتنفيذ من قبل أطرافها.</span></div>\r\n<p><a name=\"A17557_44\"></a></p>\r\n<center><span style=\"color: black;\">مادة (44)</span></center>\r\n<p><a name=\"A17557_44\"></a></p>\r\n<div><span style=\"color: black;\">1. تصدر الهيئة تعليمات الربط البيني التي تنظم أحكام الحد الأدنى من التزامات وشروط الربط بين المرخص لهم وتشمل خدمات ال');
