INSERT INTO `syndicate_goals_8364` (`id`, `date_modified`, `admin_add_id`, `date_created`, `time_stamp`, `deleted`, `restricted`, `title`) VALUES
(1, NULL, 1, '2023-01-03 12:48:52', '2023-01-03 10:48:52', 0, 0, 'To raise the scientific and professional level of programmers and technicians\r\nAnd workers in the field of informatics technology in Palestine.<>لارتقاء بالمستوى العلمي والمهني للمبرمجين والتقنيين \r\nوالعاملين في مجال المعلوماتية التكنولوجية في فلسطين.<>'),
(2, NULL, 1, '2023-01-03 12:49:09', '2023-01-03 10:49:09', 0, 0, 'To contribute and participate in national development plans and local software, technical and informatics projects on the basis of integration with the sectors of society (official, private and civil).<>لإسهام والمشاركة في خطط التنمية الوطنية والمشروعات البرمجية والتقنية والمعلوماتية المحلية على قاعدة التكامل مع قطاعات المجتمع (الرسمي والخاص والأهلي).<>'),
(3, NULL, 1, '2023-01-03 12:49:46', '2023-01-03 10:49:46', 0, 0, 'Representing union members and employers and enhancing their international presence through active participation in relevant local and international conferences and events.\r\nRepresenting union members, defending their interests, and resolving disputes.<>تمثيل أعضاء النقابة وأصحاب العمل وتعزيز الحضور الدولي من خلال المشاركة الفعالة في المؤتمرات والفعاليات المحلية والدولية ذات الصلة.\r\nتمثيل أعضاء النقابة والدفاع عن مصالحهم وحل النزاعات.<>'),
(4, '2023-01-04 09:08:53', 1, '2023-01-04 09:08:37', '2023-01-04 07:08:53', 0, 0, 'Preserving the dignity of the profession and laying down and applying the foundations that guarantee the organization of the practice of the profession and the performance of the union members of their duties in serving the country and monitoring their implementation.<>الحفاظ على كرامة المهنة وإرساء وتطبيق الأسس التي تضمن تنظيم ممارسة المهنة وأداء أعضاء النقابة لواجباتهم في خدمة الوطن ومراقبة تنفيذها.<>'),
(5, '2023-01-04 09:18:52', 1, '2023-01-04 09:10:02', '2023-01-04 07:18:52', 0, 0, 'Encouraging scientific research, developing and publishing research and studies in various programming, technical and informatics fields, and linking research to reality and developing it to serve the community.<>تشجيع البحث العلمي وتنمية ونشر البحوث والدراسات في مختلف المجالات البرمجية والتقنية والمعلوماتية وربط البحوث بالواقع وتطويرها لخدمة المجتمع.<>'),
(6, '2023-01-04 09:20:29', 1, '2023-01-04 09:20:14', '2023-01-04 07:20:29', 0, 0, 'Closer relations with all parties related to informatics sciences internally and externally.<>توثيق العلاقات مع كافة الجهات ذات الصلة بالعلوم المعلوماتية داخليا وخارجيا.<>'),
(7, '2023-01-04 09:21:24', 1, '2023-01-04 09:21:11', '2023-01-04 07:21:24', 0, 0, 'Representing union members and employers and enhancing their international presence through active participation in relevant local and international conferences and events.<>تمثيل أعضاء النقابة وأصحاب العمل وتعزيز الحضور الدولي من خلال المشاركة الفعالة في المؤتمرات والفعاليات المحلية والدولية ذات الصلة.<>'),
(8, '2023-01-04 09:22:10', 1, '2023-01-04 09:22:01', '2023-01-04 07:22:10', 0, 0, 'Representing union members, defending their interests, and resolving disputes.<>تمثيل أعضاء النقابة والدفاع عن مصالحهم وحل النزاعات.<>'),
(9, '2023-01-04 09:23:01', 1, '2023-01-04 09:22:45', '2023-01-04 07:23:01', 0, 0, 'Promote and create job opportunities for union members in the field of informatics<>تعزيز وخلق فرص عمل لأعضاء النقابة في مجال المعلوماتية<>'),
(10, '2023-01-04 09:24:04', 1, '2023-01-04 09:23:42', '2023-01-04 07:24:04', 0, 0, 'Establishing funds to support the provision of economic, social, cultural and recreational services to members and organizing the old age, disability and death pension due to a union member.<>إنشاء صناديق لدعم تقديم الخدمات الاقتصادية والاجتماعية والثقافية والترفيهية للأعضاء وتنظيم معاش الشيخوخة والعجز والوفاة المستحق لعضو النقابة.<>'),
(11, '2023-01-04 09:24:38', 1, '2023-01-04 09:24:26', '2023-01-04 07:24:38', 0, 0, 'Publication of the activities and events of the Syndicate and specialized scientific research.<>نشر نشاطات وفعاليات النقابة والابحاث العلمية المختصة.<>'),
(12, '2023-01-04 09:25:37', 1, '2023-01-04 09:25:13', '2023-01-04 07:25:37', 0, 0, 'Strengthening and developing the union\'s role in partnership with the official, public and private sectors.<>تعزيز وتطوير دور النقابة في الشراكة مع القطاع الرسمي والعام والخاص.<>'),
(13, '2023-01-04 09:26:05', 1, '2023-01-04 09:25:51', '2023-01-04 07:26:05', 0, 0, 'Protecting the legitimate rights of union members, defending their rights, taking care of their interests, and improving their terms and conditions of work.<>حماية الحقوق المشروعة لأعضاء النقابة والدفاع عن حقوقهم ورعاية مصالحهم وتحسين شروط وظروف عملهم.<>'),
(14, '2023-01-04 09:26:31', 1, '2023-01-04 09:26:17', '2023-01-04 07:26:31', 0, 0, 'Developing cultural and professional awareness and raising the social, health and economic level of its members.<>تنمية الوعي الثقافي والمهني ورفع المستوى الاجتماعي والصحي والاقتصادي لأعضائها.<>');
INSERT INTO `trainings_and_workshops_8419` (`id`, `date_modified`, `admin_add_id`, `date_created`, `time_stamp`, `deleted`, `restricted`, `title`, `summary`, `content`, `photo`, `publish_date`) VALUES
(1, '2023-09-06 08:47:23', 1, '2023-05-11 11:17:08', '2023-09-06 05:47:23', 0, 0, 'software development processes and build quality products Training<>دورة تدريبية مجانية تحت عنوان \"software development processes and build quality products\"<>', 'https://forms.gle/P9hCEoBjgPu6G2Fb9\r\n<><>', '<><p>تعلن نقابة العلوم المعلوماتية التكنولوجية عن فتح باب التسجيل لدوره تخصصية تحت عنوان software development processes and build quality products، مع العلم ان:<br />1. عدد الساعات التدريبية: 150 ساعه.<br />2. عدد ايام الدورة: 23 يوم تدريبي (Full Day) وجاهيا في مدينة رام الله.<br />3. عدد المقاعد (20) فقط.<br />4. سيتم في نهاية الدورة توزيع شهادات اتمام الدورة.<br />5. ان يكون المتقدم / المتقدمة منتسبا للنقابة ومسددا لاشتراكاته السنوية علما ان الاولوية ستكون للخريجين الجدد.<br />6. على من يتم قبول تسجيله الالتزام بحضور ما يعادل 75% من لقاءات الدورة على الاقل، وفي حال عدم الالتزام سيعتبر المسجل منسحب من الدورة ويتحمل تكاليف المقعد كاملة.<br />7. سيتم اختيار المتقدمين بناء على الاولوية والبيانات المرفقة في طلب التسجيل.<br />8. توقيع تعهد التزام بالدورة لمن يتم قبول طلبات انضمامهم للدورة بما فيها الالتزام بدفع رسوم الدورة في حال الاخلال بالشروط اعلاه.<br />يمكن تقديم طلب الترشح من خلال الرابط أدناه:<br />https://forms.gle/P9hCEoBjgPu6G2Fb9</p><>', '1693308726961679705.jpg', NULL),
(2, '2023-09-06 08:46:10', 1, '2023-05-11 11:17:08', '2023-09-06 05:46:10', 0, 0, 'Oracle Database ,PL/SQL<>دورة تخصصية (Oracle Database ,PL/SQL) بهدف التوظيف<>', '<><>', '<><p>دعوة للتسجيل في دورة تخصصية (Oracle Database ,PL/SQL) بهدف التوظيف<br />بناء على اتفاقية التعاون الموقعة مع شركة اكسبرتس للحلول المتكامله، تدعوكم النقابة للتسجيل في دورة تدريبية تخصصية لبرنامج PL/SQL وتدريب Oracle Database، حيث يتوفر عدد (3) مقاعد لهذه الدورة.<br />هذا وسيتم ربط المتدربين المؤهلين بعد انتهاء الدورة مع شركات فلسطينية لغايات توظيفهم في هذه الشركات. علما بان الدورة ستبدأ بتاريخ 2023/09/05 وسيتم عقدها في معهد اكسبرتس الواقع في مدينة رام الله بواقع 72 ساعة تدريبية.<br />شروط التقدم للتدريب والتوظيف:<br />- ان يكون المتقدم منتسب للنقابة.<br />- ان يكون المتقدم من 18-35 عام.<br />- ان يكون المتقدم عاطلا عن العمل.<br />- ان يكون من سكان محافظة رام الله والبيره.<br />- الالتزام الكامل بالمشاركة في التدريب حتى النهاية.<br />- توقيع تعهد التزام.<br />على من يجد في نفسه الرغبه تعبئة النموذج ادناه علما ان آخر موعد للتسجيل هو الاحد الموافق 2023/08/27.<br />https://forms.gle/BUZE6aMTc1LUvC1M6</p><>', '1693805984109758064.jpg', NULL),
(9, NULL, 1, '2023-09-13 12:00:11', '2023-09-13 09:03:38', 1, 0, 'ff<><>', 'dff<><>', '<><>', '', NULL),
(3, '2023-09-06 08:46:36', 1, '2023-05-11 11:17:08', '2023-09-06 05:46:36', 0, 0, 'Internet of Things Workshops<> تحدي فلسطين لإنترنت الأشياء<>', '<><>', '<><p>صنع في فلسطين - تحدي فلسطين لإنترنت الأشياء<br />كشريك رئيسي، تدعوكم مؤسسة النيزك ونقابة العلوم المعلوماتية التكنولوجية الفلسطينية للتسجيل في \"تحدي فلسطين لإنترنت الأشياء\". علما بأن الموعد النهائي للتسجيل هو: 22 يوليو 2023<br />التسجيل من خلال الرابط: https://alnayzak.org/applications/iot</p><>', '16938062202100922254.jpg', NULL),
